const logo =
  'data:image/png;base64,';

const fs = require("fs");
const path = require("path");

const fontBase64 = fs.readFileSync(
  path.join(__dirname, "../assets/myFont.ttf"),
  "base64"
);


const getQuoteHtml = (quote) => {
  const formatCurrency = (amount) =>
    `${quote.currency} ${Number(amount || 0).toLocaleString(undefined, {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })}`;

  const capitalize = (value) => {
    if (!value || typeof value !== "string") return "";
    return value.toLowerCase().replace(/\b\w/g, (c) => c.toUpperCase());
  };

  const otherTaxRows = (quote.otherTax || [])
    .map(
      (t) => `
      <tr>
        <td>${t.tax.toUpperCase()} (${t.percent}%)</td>
        <td class="text-right">
          ${formatCurrency(
            (quote.subTotal - quote.discountTotal) *
              (Number(t.percent) / 100)
          )}
        </td>
      </tr>
    `
    )
    .join("");

  return `
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">

<style>

@font-face {
  font-family: "CourierNewBold";
  src: url(data:font/ttf;base64,${fontBase64})
       format("truetype");
  font-weight: bold;
}

body {
  font-family: "CourierNewBold";
  margin: 0;
  padding: 30px;


  font-size: 10px;
}

.container {
  width: 100%;
  max-width: 900px;
  margin: auto;


}

/* HEADER */

.header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
}

.logo img {
  width: 260px;
}

.title-box {
  text-align: left;
}

.doc-title {
  background: #000;
  color: #fff;
  padding: 10px 60px;
  font-weight: bold;
  margin-bottom: 10px;
  display: inline-block;
}

.info td {
  padding: 2px 10px;
}

.light {
  font-size: 10px;
  color: #444;
}

/* COMPANY + CUSTOMER */

.section {
  display: flex;
  justify-content: space-between;
  margin-top: 30px;
}

.box {
  width: 48%;
}

.box-title {
  background: #000;
  color: #fff;
  padding: 6px;
  text-align: center;
  font-weight: bold;
  margin-bottom: 10px;
}

/* TABLE */

table {
  width: 100%;
  border-collapse: collapse;
}

.items {
  margin-top: 30px;
}

.items th {
  text-align: left;
  padding: 8px;
  border-bottom: 2px solid #000;
}

.items td {
  padding: 10px 8px;
  border-bottom: 1px solid #ddd;
}

.text-right {
  text-align: right;
}

/* TOTALS */

.totals {
  margin-top: 10px;
  width: 320px;
  float: right;
}

.totals td {
  padding: 6px;
}

.totals .grand {
  font-weight: bold;
  border-top: 2px solid #000;
}

/* TERMS */

.terms {
  margin-top: 60px;
}

.footer {
  margin-top: auto;
  text-align: center;
  font-size: 11px;
  color: #444;
}

.items {
  page-break-inside: auto;
}

tr {
  page-break-inside: avoid;
}

.totals {
  page-break-inside: avoid;
}

.terms {
  page-break-inside: avoid;
}

html, body {
  height: auto;
}

.container {
  width: 100%;
  max-width: 900px;
  margin: auto;
}

/* CRITICAL FOR PDF */

.footer {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;

  height: 120px;

  text-align: center;
  font-size: 11px;
  color: #444;

  border-top: 1px solid #000;

  background: #fff;

  padding-top: 10px;
}
.footer-space {
  height: 130px;
}

/* Prevent bad page breaks */

.items {
  page-break-inside: auto;
}

thead {
  display: table-header-group;
}

tfoot {
  display: table-footer-group;
}

tr {
  page-break-inside: avoid;
}

.totals {
  page-break-inside: avoid;
  margin-top: 20px;
}

.terms {
  page-break-inside: avoid;
}

</style>

</head>

<body>

<div class="container">

<!-- HEADER -->

<div class="header">

  <div class="logo">
    <img src="${logo}" />
  </div>

  <div class="title-box">

    <br/>
    <br/>

    <div class="doc-title">
      QUOTATION
    </div>

    <table class="info light">

      <tr>
        <td>Quote No:</td>
        <td>${quote.quoteNumber}</td>
      </tr>

      <tr>
        <td>Date:</td>
        <td>${new Date(
          quote.createdAt
        ).toLocaleDateString()}</td>
      </tr>

      <tr>
        <td>Valid Until:</td>
        <td>${
          quote.validUntil
            ? new Date(quote.validUntil).toLocaleDateString()
            : "-"
        }</td>
      </tr>

    </table>

  </div>

</div>

<!-- COMPANY + CUSTOMER -->

<div class="section">

  <div class="box">

    <div class="box-title">
      COMPANY
    </div>

    <b>TECHSYNERGY INNOVATIONS (PRIVATE) LIMITED</b>

    <p class="light">
      Plot 47-C, Mezzanine Floor, 21st Street<br/>
      Phase II Extension, DHA, Karachi<br/>
      Website: www.techsynergypk.com<br/>
      Email: sales@techsynergypk.com<br/>
      NTN: G141420
    </p>

  </div>

  <div class="box">

    <div class="box-title">
      CUSTOMER
    </div>

    <b>
      ${capitalize(
        quote.account?.accountName || ""
      )}
    </b>

    <p class="light">
      ${capitalize(
        quote.contact?.email || ""
      )}
    </p>

  </div>

</div>

<!-- INTRO -->

<br/>

<p>
Dear ${capitalize(
    quote.contact?.firstName || "Sir/Madam"
  )},<br/>
</p>
<p class="light">
We are pleased to submit our formal quotation
as per your requirement.
Please find the commercial details below:
</p>

<!-- ITEMS -->

<table class="items">

<thead>

<tr>
<th style="width:5%">S.No</th>
<th style="width:20%">Product</th>
<th>Description</th>
<th style="width:15%">Unit Price</th>
<th style="width:10%">Qty</th>
<th style="width:15%">Line Total</th>
</tr>

</thead>

<tbody class="light">

${quote.products
  .map(
    (p, i) => `
<tr>

<td>${i + 1}</td>

<td>
${capitalize(p.productName)}
</td>

<td>
${p.description}
</td>

<td class="text-right">
${formatCurrency(p.listPrice)}
</td>

<td class="text-right">
${p.quantity}
</td>

<td class="text-right">
${formatCurrency(p.total)}
</td>

</tr>
`
  )
  .join("")}

</tbody>

</table>

<!-- TOTALS -->

<table class="totals">

<tr>
<td>Subtotal</td>
<td class="text-right">
${formatCurrency(quote.subTotal)}
</td>
</tr>

${
  quote.discountTotal
    ? `
<tr>
<td>Discount</td>
<td class="text-right">
${formatCurrency(quote.discountTotal)}
</td>
</tr>
`
    : ""
}

${
  quote.isGstApplied
    ? `
<tr>
<td>GST (18%)</td>
<td class="text-right">
${formatCurrency(quote.gstAmount)}
</td>
</tr>
`
    : ""
}

${otherTaxRows}

<tr class="grand">
<td>Total</td>
<td class="text-right">
${formatCurrency(quote.grandTotal)}
</td>
</tr>

</table>

<!-- TERMS -->

<div class="terms">

<b>Terms & Conditions:</b>

<ul>

${
  quote.validUntil
    ? `
<li>
This quotation is valid until
${new Date(
  quote.validUntil
).toLocaleDateString()}
</li>
`
    : ""
}

${(quote.termsAndConditions || [])
  .map((t) => `<li>${capitalize(t)}</li>`)
  .join("")}

</ul>

<br/>

<b>Best Regards,</b><br/>

${capitalize(
  quote.quoteOwner?.name || ""
)}<br/>

${quote.quoteOwner?.email || ""}<br/>

TechSynergy Innovations Pvt. Ltd.

</div>

<!-- FOOTER -->
<div class="footer-space"></div>

<!-- FOOTER -->

<div class="footer">
<div class="footer">

47-C, Mezz Floor, DHA Phase II Ext, Karachi
<br/>

www.techsynergypk.com
|
info@techsynergypk.com
|
0337-8328310

</div>

</div>

</body>

</html>
`;
};

module.exports = getQuoteHtml;